    public AutomationsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Lead Assignment Rules (Article) ──────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Lead Assignment Rules",
            Slug = "assignment-rules-overview",
            Summary = "How to create priority-ordered rules that automatically route incoming leads to the right rep: Round Robin, Territory, Industry, and Account-Based kinds.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","routing"]""",
            ContentJson = """{"body":"## Lead Assignment Rules\n\nAssignment rules decide which sales rep a new lead is routed to, automatically, the moment the lead is created. Instead of someone hand-picking an owner for every lead, you define a small set of rules once and the system applies them for you. This page — Admin → Assignment Rules — is where those rules live.\n\n### How rules are evaluated\n\nRules are evaluated **in priority order**, lowest number first. The first **active** rule that matches the incoming lead wins, and that rule decides the assignee. A rule that is toggled off is skipped entirely. Because the first match wins, ordering matters: put your most specific rules (a particular territory, a key account) at a lower priority number so they are checked before broad catch-all rules.\n\nThink of it as a waterfall: the lead drops through the active rules from the lowest priority number down, and lands on the first one whose conditions it satisfies.\n\n### Rule Kinds\n\nEvery rule has a **Kind** that determines both how it matches a lead and how it picks a rep:\n\n- **Round Robin** — distributes leads evenly across a pool of reps. You list the rep IDs that participate, and the system hands each new lead to the next rep in rotation. Use this for a general intake queue where any qualified rep can take the lead.\n- **Territory** — matches leads by geography. You specify the U.S. state codes and/or ZIP-code prefixes the rule covers; a lead whose address falls inside that territory is routed to the rule's owner. Use this when reps own regions.\n- **Industry** — matches leads by the industry they belong to. You list the industry values the rule covers. Use this when reps specialize by vertical (aerospace, medical, automotive, etc.).\n- **Account-Based** — routes a lead to whoever already owns the account (B2B grouping) the lead belongs to, so every contact at a company lands with the same rep. This kind needs no extra match fields — the account linkage drives it.\n\n### Creating a rule\n\nClick **New Rule** to open the rule dialog. Every rule needs three things:\n\n1. **Name** — a human label so you can recognize the rule in the list (e.g., \"West Coast Territory\", \"Aerospace Specialists\").\n2. **Kind** — pick one of the four kinds above. Choosing a kind reveals the fields that kind needs.\n3. **Priority** — the evaluation order number (lower = checked first). Two rules can share a number, but giving each a distinct priority keeps the waterfall predictable.\n\nThen fill the **kind-specific fields** the dialog shows:\n\n- Round Robin → **Rep IDs** (a comma-separated list of user IDs to rotate through).\n- Territory → **States** and/or **ZIP Prefixes** (comma-separated). State codes are stored upper-cased automatically.\n- Industry → **Industries** (comma-separated industry values).\n- Account-Based → no extra fields; a hint reminds you the account linkage does the work.\n\nClick **Save** to create the rule. New rules are active by default.\n\n### Editing, activating, and deleting\n\n- **Edit** (the pencil icon, or clicking the row) reopens the dialog. When editing, an **Active** toggle appears so you can pause a rule without deleting it — a paused rule is skipped during evaluation but kept for later.\n- **Delete** (the trash icon) removes a rule after a confirmation prompt. Deleting is permanent for the rule definition; existing lead assignments are not changed.\n\n### The raw spec escape hatch\n\nUnder the kind-specific fields is a collapsible **Advanced / Raw Spec** section containing a JSON text area. The structured fields above are the normal way to configure a rule — the system serializes them to JSON for you. The raw spec is a fallback for power users: if a kind ever needs a shape the form doesn't surface yet, you can paste the JSON directly. When the structured fields are filled in, they win; the raw box is only used when the structured fields are empty. Most admins never need to touch it.\n\n### Capability and permissions\n\nAssignment rules are gated by the lead capability (CAP-O2C-LEAD) and are an Admin/Manager surface. Creating and editing rules requires the Admin or Manager role; deleting a rule requires Admin.","sections":[]}"""
        });

        // ── Assignment Rules Field Reference (QuickRef) ──────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules Field Reference",
            Slug = "assignment-rules-field-reference",
            Summary = "Reference for the Assignment Rules list columns, the rule dialog fields, each Kind's spec shape, validation rules, and the raw-spec fallback.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","reference"]""",
            ContentJson = """{"title":"Assignment Rules Field Reference","groups":[{"heading":"List Columns","items":[{"label":"Priority","value":"Sortable, right-aligned. The evaluation order number — lower numbers are checked first. The first active rule that matches a lead wins."},{"label":"Name","value":"Sortable. The human label for the rule."},{"label":"Kind","value":"Sortable. Shown as an info chip: Round Robin, Territory, Industry, or Account-Based."},{"label":"Active","value":"Sortable, centered. A green Active chip or a muted Inactive chip. Inactive rules are skipped during evaluation."},{"label":"Created","value":"Sortable, date. When the rule was created (MM/dd/yyyy)."},{"label":"Actions","value":"Row-level Edit (pencil) and Delete (trash) buttons. Clicking the row body also opens Edit."}]},{"heading":"Rule Dialog — Common Fields","items":[{"label":"Name (required)","value":"Text input, up to 100 characters. Identifies the rule in the list."},{"label":"Kind (required)","value":"Select: Round Robin, Territory, Industry, Account-Based. Changing it swaps the kind-specific fields shown below."},{"label":"Priority (required)","value":"Number input. Evaluation order; lower is checked first. Defaults to 100 for a new rule."},{"label":"Active (edit only)","value":"Toggle, shown only when editing an existing rule. Off pauses the rule without deleting it. New rules are active by default."}]},{"heading":"Round Robin — Spec Fields","items":[{"label":"Rep IDs","value":"Comma-separated list of user IDs to rotate through. Each new matching lead is handed to the next rep in the rotation. Serialized to {\"repIds\":[...]}"}]},{"heading":"Territory — Spec Fields","items":[{"label":"States","value":"Comma-separated U.S. state codes the territory covers. Stored upper-cased automatically (ca → CA)."},{"label":"ZIP Prefixes","value":"Comma-separated ZIP-code prefixes the territory covers. Either States or ZIP Prefixes (or both) defines the territory. Serialized to {\"states\":[...],\"zipPrefixes\":[...]}"}]},{"heading":"Industry — Spec Fields","items":[{"label":"Industries","value":"Comma-separated industry values the rule covers. A lead in one of these industries is routed by this rule. Serialized to {\"industries\":[...]}"}]},{"heading":"Account-Based — Spec Fields","items":[{"label":"(none)","value":"Account-Based rules need no extra match fields — a hint in the dialog explains the rule routes the lead to the owner of the account it belongs to. The spec is stored empty."}]},{"heading":"Advanced — Raw Spec","items":[{"label":"Raw Spec (collapsible)","value":"A JSON text area (up to 4000 chars) under a collapsible Advanced section. A fallback for kinds whose form fields aren't surfaced yet. Used only when the structured fields are empty — otherwise the structured fields win and overwrite it."}]},{"heading":"Validation & Behavior","items":[{"label":"First active match wins","value":"Rules evaluate in ascending priority order; the first active matching rule decides the assignee. Inactive rules are skipped."},{"label":"Name required","value":"Save is blocked until a name is entered (max 100 chars)."},{"label":"Kind required","value":"Save is blocked until a kind is chosen."},{"label":"Priority required","value":"Save is blocked until a priority number is entered."},{"label":"State upper-casing","value":"Territory state codes are normalized to upper-case on save."},{"label":"Default active","value":"A newly created rule is active immediately. Use the Active toggle (edit mode) to pause it later."}]},{"heading":"Permissions","items":[{"label":"View / Create / Edit","value":"Admin or Manager role. Gated by CAP-O2C-LEAD."},{"label":"Delete","value":"Admin role only."}]}]}"""
        });

        // ── Assignment Rules Walkthrough ─────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules — Guided Tour",
            Slug = "assignment-rules-walkthrough",
            Summary = "A guided tour of the Assignment Rules admin page: the rules table, priority ordering, the New Rule action, and the per-row edit/delete controls.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","walkthrough"]""",
            ContentJson = """{"appRoute":"/admin/assignment-rules","startButtonLabel":"Tour Assignment Rules","steps":[{"element":".toolbar__hint","popover":{"title":"Lead Assignment Rules","description":"This page holds the rules that route new leads to reps automatically. Rules are evaluated in priority order, and the first active rule that matches a lead decides its owner.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Rules Table","description":"Each row is one rule: its Priority (the evaluation order — lower numbers are checked first), Name, Kind (Round Robin, Territory, Industry, or Account-Based), whether it's Active, and when it was created. Click the Priority header to sort and see the waterfall order your leads actually fall through.","side":"top"}},{"element":"[data-testid='assignment-rule-new-btn']","popover":{"title":"New Rule","description":"Click here to add a rule. The dialog asks for a Name, a Kind, and a Priority, then reveals the fields that kind needs — rep IDs for Round Robin, states/ZIP prefixes for Territory, industries for Industry. Account-Based needs no extra fields. New rules are active right away.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Edit, Pause, or Delete","description":"Use the pencil on a row (or click the row) to reopen the dialog — in edit mode an Active toggle lets you pause a rule without deleting it. The trash icon deletes a rule after a confirmation. Lower a rule's priority number to make it win over broader rules below it.","side":"top"}}]}"""
        });

        // ── Assignment Rules Knowledge Check (Quiz) ──────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Assignment Rules Knowledge Check",
            Slug = "assignment-rules-quiz",
            Summary = "Test your understanding of lead assignment rules: priority evaluation, the four rule kinds, kind-specific fields, and pausing vs deleting.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["admin","automations","leads","assignment","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":6,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ar1","text":"You have several active assignment rules. Which one decides where a new lead goes?","options":[{"id":"a","text":"The first active rule, in ascending priority order, whose conditions the lead matches","isCorrect":true},{"id":"b","text":"The rule with the highest priority number"},{"id":"c","text":"All matching rules apply, and the lead is split among their reps"},{"id":"d","text":"The most recently created rule"}],"explanation":"Rules are evaluated in ascending priority order (lowest number first). The first active rule that matches the lead wins and decides the assignee. Inactive rules are skipped, and once a rule matches, evaluation stops."},{"id":"ar2","text":"Which rule Kind distributes incoming leads evenly across a pool of reps?","options":[{"id":"a","text":"Round Robin","isCorrect":true},{"id":"b","text":"Territory"},{"id":"c","text":"Industry"},{"id":"d","text":"Account-Based"}],"explanation":"Round Robin lists a set of rep IDs and hands each new matching lead to the next rep in rotation, spreading leads evenly. Territory matches by geography, Industry by vertical, and Account-Based by the account the lead belongs to."},{"id":"ar3","text":"You want reps to own U.S. regions so a lead in California always goes to the West-coast rep. Which Kind and fields do you use?","options":[{"id":"a","text":"Territory, specifying state codes and/or ZIP-code prefixes","isCorrect":true},{"id":"b","text":"Round Robin, listing every rep's ID"},{"id":"c","text":"Industry, listing California as an industry"},{"id":"d","text":"Account-Based, with no extra fields"}],"explanation":"Territory rules match leads by geography. You enter the state codes (e.g., CA) and/or ZIP-code prefixes the territory covers, and leads whose address falls inside that territory route to the rule's owner. State codes are stored upper-cased automatically."},{"id":"ar4","text":"You want to stop using a rule for now but keep its configuration for later. What's the best action?","options":[{"id":"a","text":"Edit the rule and turn off its Active toggle","isCorrect":true},{"id":"b","text":"Delete the rule and re-create it later"},{"id":"c","text":"Set its priority to 0"},{"id":"d","text":"Clear all of its spec fields"}],"explanation":"Editing a rule reveals an Active toggle. Turning it off pauses the rule — it's skipped during evaluation but its definition is retained, so you can re-enable it later. Deleting removes the rule permanently."},{"id":"ar5","text":"You create a new Account-Based rule. Why doesn't the dialog ask for states, rep IDs, or industries?","options":[{"id":"a","text":"Account-Based routes a lead to whoever already owns the account the lead belongs to, so no extra match fields are needed","isCorrect":true},{"id":"b","text":"Account-Based rules are not configurable and only run nightly"},{"id":"c","text":"You must enter those fields in the raw spec JSON instead"},{"id":"d","text":"Account-Based is a placeholder kind that does nothing"}],"explanation":"Account-Based rules use the account (B2B grouping) linkage to route a lead to the rep who already owns that account, keeping all of a company's contacts with one rep. Because the account relationship drives the assignment, the dialog shows a hint instead of extra match fields."},{"id":"ar6","text":"Two rules could match the same lead: a broad catch-all and a specific key-account rule. How do you make the specific rule win?","options":[{"id":"a","text":"Give the specific rule a lower priority number than the catch-all so it's evaluated first","isCorrect":true},{"id":"b","text":"Give the specific rule a higher priority number than the catch-all"},{"id":"c","text":"Mark the catch-all as inactive permanently"},{"id":"d","text":"Delete the catch-all rule"}],"explanation":"Because the first active match wins and rules evaluate from the lowest priority number up, putting the specific rule at a lower number means it's checked before the broad catch-all. The specific rule matches first, so it decides the assignee and the catch-all is never reached for that lead."}]}"""
        });

        // ── Auto-PO Admin Settings (Article) ─────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Auto-PO Settings (Admin)",
            Slug = "auto-po-admin-overview",
            Summary = "The Admin → Auto-PO settings panel: enabling automatic purchasing, choosing Suggest/Draft/Automatic mode, the buffer days, chat notifications, and the nightly demand-analysis job.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/admin/auto-po"]""",
            Tags = """["admin","automations","auto-po","purchasing","procurement"]""",
            ContentJson = """{"body":"## Auto-PO Settings (Admin)\n\nAuto-PO is the feature that watches demand for purchased parts and proposes (or raises) purchase orders to cover it, so a buyer doesn't have to notice every shortfall by hand. This admin panel — Admin → Auto-PO — is where you turn that automation on and decide how aggressive it is. The proposals it produces are reviewed on the **Suggestions** tab of the Purchase Orders page; this page is purely the configuration.\n\n### How Auto-PO works at a glance\n\nA background **demand-analysis job runs nightly**. It looks at demand for purchased parts (driven by sales orders and other consumers), compares it against on-hand stock and incoming POs, and where there's a projected shortfall it raises an Auto-PO suggestion for the part's preferred vendor. What happens to that suggestion next depends on the **mode** you choose below. Admins who don't want to wait for the nightly run can trigger an analysis on demand from the Suggestions surface (Run Analysis).\n\n### The settings\n\n**Enable Auto-PO** — the master switch. When off, no suggestions are generated and the nightly job does nothing. Turn it on to start the automation.\n\n**Mode** — controls how far the automation goes on its own:\n- **Suggest** — the job only creates suggestions. A buyer reviews them on the Suggestions tab and decides which to convert into purchase orders. This is the most conservative setting and the usual starting point.\n- **Draft** — the job goes one step further and creates **draft** purchase orders from the suggestions, ready for a buyer to review and submit. Nothing is sent to a vendor automatically; a human still presses Submit.\n- **Automatic** — the job creates and advances the purchase orders without manual review. Use this only once you trust the demand signal and vendor data, because it acts without a person in the loop.\n\n**Buffer Days** — a safety lead-time cushion. Auto-PO treats the need date as earlier by this many days so orders are placed with slack before the part is actually required. A larger buffer orders sooner (more safety, more on-hand inventory); a smaller buffer orders later (leaner, less margin for delay).\n\n**Notify Chat** — when enabled, Auto-PO posts to chat when it raises suggestions or orders, so the purchasing team is alerted without watching the Suggestions tab. Turn it off to keep the automation silent.\n\nClick **Save** to persist the settings. They take effect on the next analysis run (or the next on-demand run).\n\n### Choosing a mode in practice\n\nMost installs start in **Suggest** to build confidence — you can see what Auto-PO *would* order before letting it act. As the part and vendor data prove reliable, teams move to **Draft** so the busywork of opening POs is done for them while a buyer still approves each one. **Automatic** is reserved for steady, well-understood replenishment where hands-off ordering is genuinely safe.\n\n### Where the suggestions go\n\nThis page never lists suggestions — it only configures the engine. To review, convert, dismiss, or bulk-convert the proposals Auto-PO produces, go to **Purchase Orders → Suggestions**. See the related Auto-PO suggestions training for that workflow.\n\n### Capability and permissions\n\nAuto-PO is gated by the auto-PO capability (CAP-P2P-AUTOPO). These settings are an Admin surface; reviewing and converting suggestions is open to Admin, Manager, and Office Manager.","sections":[]}"""
        });

        // ── Automations Advanced Reference (Reference) ───────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Automations / Assignment Rules / Auto-PO — Advanced Reference",
            Slug = "automations-reference",
            Summary = "Edge-case reference for the Automations admin surfaces: spec serialization and the raw-JSON fallback, assignment-rule validation and Territory upper-casing, per-action role gating, and the Auto-PO system-setting keys and SO/PO status sets.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/assignment-rules"]""",
            Tags = """["automations","reference","advanced"]""",
            ContentJson = """{"body":"## Raw-JSON Spec Fallback & Serialization\n\nEach `AssignmentRule` stores its kind-specific match parameters in a single nullable `Spec` column (JSON text, max 4000 chars). The admin dialog renders Kind-specific structured fields and serializes them client-side — admins normally never see raw JSON.\n\nSerialized shapes by Kind:\n\n- **RoundRobin** -> `{\"repIds\":[...]}` (list of user IDs; non-numeric/blank entries dropped).\n- **Territory** -> `{\"states\":[...],\"zipPrefixes\":[...]}` — either key omitted when its list is empty.\n- **Industry** -> `{\"industries\":[...]}`.\n- **AccountBased** -> `null` Spec (the account linkage drives routing; no match payload).\n\nThe **raw-spec escape hatch** is the `specRaw` textarea under the collapsible Advanced section. `buildSpec()` only falls back to the raw value when the kind's structured fields are all empty; whenever structured fields are populated, they win and overwrite whatever is in the raw box. The server (`CreateAssignmentRuleHandler` / `UpdateAssignmentRuleHandler`) stores the `Spec` string verbatim after a trim — it does not parse or validate the JSON shape, so a malformed raw spec is accepted at write time and only fails when the matching engine reads it.\n\n## Assignment-Rule Validation & Territory Upper-Casing\n\nServer-side validation in the create/update handlers is intentionally thin:\n\n- **Name** — required; rejected with `InvalidOperationException(\"Rule name is required.\")` when blank on create. Stored trimmed.\n- **Priority** — plain `int`; lower numbers are evaluated first (ties broken alphabetically by Name in the GET ordering). No range check.\n- **Spec** — stored trimmed; not schema-validated server-side.\n- **IsActive** — defaults `true` on create; the Active toggle is edit-only.\n\n**Territory upper-casing** happens client-side during serialization: `parseStringList(specStates).map(s => s.toUpperCase())` normalizes state codes (e.g., `ca` -> `CA`) before they go into the Spec. ZIP prefixes are NOT upper-cased. Because normalization lives in `buildSpec()`, a state code injected through the raw-spec textarea bypasses it and is stored as-typed.\n\n`UpdateAssignmentRuleHandler` follows the rollup rule — one activity row per save summarizing changed fields (`Updated N field(s): ...`), under the kebab verbs `assignment-rule-created` / `assignment-rule-updated` / `assignment-rule-deleted`. Delete is a soft delete (`DeletedAt` stamped).\n\n## Capability & Per-Action Role Gating\n\nBoth surfaces are capability-gated and additionally split roles by action.\n\n**Assignment Rules** (`AssignmentRulesController`, gated `CAP-O2C-LEAD`):\n\n- Controller-wide `[Authorize(Roles = \"Admin,Manager\")]` — Get / Create / Update.\n- `DELETE /{id}` adds `[Authorize(Roles = \"Admin\")]` — only Admin may delete a rule.\n\n**Auto-PO** (`AutoPoController`, gated `CAP-P2P-AUTOPO`):\n\n- Controller-wide `[Authorize(Roles = \"Admin,Manager,OfficeManager\")]` — covers reviewing suggestions (`GET /suggestions`), `convert`, `dismiss`, and `bulk-convert`.\n- `GET /settings`, `PATCH /settings`, and `POST /run` (manual trigger) each add `[Authorize(Roles = \"Admin\")]` — settings and on-demand analysis are Admin-only; Managers/Office Managers can act on suggestions but not change configuration.\n\nWhen a capability is disabled the request short-circuits with 403 before the role check via `CapabilityGateMiddleware`.\n\n## Auto-PO System-Setting Keys & SO/PO Status Sets\n\nAuto-PO has no dedicated settings table — configuration lives in four `SystemSetting` rows, all under the `inventory:` prefix:\n\n- `inventory:auto_po_enabled` — master switch (bool; default `false`).\n- `inventory:auto_po_mode` — `Suggest` / `Draft` / `Automatic` (default `Draft`).\n- `inventory:auto_po_buffer_days` — int safety lead-time cushion (default `3`).\n- `inventory:auto_po_notify_chat` — bool (default `true`).\n\n`UpdateAutoPoSettingsValidator` enforces Mode in {Suggest, Draft, Automatic} and BufferDays in [0, 30]. The settings response also carries a fixed `Schedule` string (\"Daily at 6:00 AM UTC\") — the nightly `AutoPurchaseOrderJob` cadence is not itself a stored setting.\n\n**Status sets the nightly job keys off of** (`AutoPurchaseOrderJob`):\n\n- **Active SO statuses** (demand sources): `Confirmed`, `InProduction`, `PartiallyShipped` — only lines where `Quantity > ShippedQuantity` count.\n- **Open PO statuses** (in-transit supply, netted against demand): `Draft`, `Submitted`, `Acknowledged`, `PartiallyReceived`.\n\nDemand explodes Buy-source BOM lines (skipping parts flagged `ExcludeFromAutoPo`), nets shortfall against on-hand + in-transit + safety stock, then per vendor: **Suggest** mode writes one `AutoPoSuggestion` per part (Status `Pending`, dedup-guarded against existing Pending suggestions); **Draft**/**Automatic** batch items whose needed-by dates fall within 7 days into POs — `Automatic` opens them as `Submitted`, `Draft` as `Draft`. A vendor's own `AutoPoMode` overrides the global mode. Source SO IDs are JSON-serialized onto the suggestion/PO notes. Admins/Managers/Office Managers are notified; review happens on Purchase Orders -> Suggestions, not on this admin page.","sections":[]}"""
        });

        Log.Information("Seeded Automations training modules");
    }
}
